691	            .expect((res: any) => assert.equal(res.body.code, 0));
692	      };
693	
694	      const origHtml = await getHtml(sourcePadId);
695	      assert.doesNotMatch(origHtml, /<strong>/);
696	      assert.doesNotMatch(origHtml, /<em>/);
697	      await agent.get(`${endPoint('copyPadWithoutHistory')}?sourceID=${sourcePadId}` +
698	                      `&destinationID=${newPad}&force=false`)
699	          .set("Authorization", (await common.generateJWTToken()))
700	          .expect(200)
701	          .expect('Content-Type', /json/)
702	          .expect((res:any) => assert.equal(res.body.code, 0));
703	
704	      const newBodySrc = '<strong>bold</strong>';
705	      const newBodyDst = '<em>italic</em>';
706	      await setBody(sourcePadId, newBodySrc);
707	      await setBody(newPad, newBodyDst);
708	      await setBody(sourcePadId, `${newBodySrc} foo`);
709	
710	      let [srcHtml, dstHtml] = await Promise.all([getHtml(sourcePadId), getHtml(newPad)]);
711	      assert.match(srcHtml, new RegExp(newBodySrc));
712	      assert.match(dstHtml, new RegExp(newBodyDst));
713	
714	      // Force the server to re-read the pads from the database. This rebuilds the attribute pool
715	      // objects from scratch, ensuring that an internally inconsistent attribute pool object did
716	      // not cause the above tests to accidentally pass.
717	      const reInitPad = async (padId:string) => {
718	        const pad = await padManager.getPad(padId);
719	        await pad.init();
720	      };
721	      await Promise.all([
722	        reInitPad(sourcePadId),
723	        reInitPad(newPad),
724	      ]);
725	
726	      [srcHtml, dstHtml] = await Promise.all([getHtml(sourcePadId), getHtml(newPad)]);
727	      assert.match(srcHtml, new RegExp(newBodySrc));
728	      assert.match(dstHtml, new RegExp(newBodyDst));
729	    });
730	  });
731	});
