  before(async function () {
    agent = await common.init();
    const res = await agent.get('/api/')
        .expect(200)
        .expect('Content-Type', /json/);
    apiVersion = res.body.currentVersion;
    assert(apiVersion);
  });

  describe('createDiffHTML', function () {
    before(async function () {
      // Create a pad
      const res = await agent.get(
          `${endPoint('createPad')}?padID=${testPadId}&text=testText`)
          .set("Authorization", (await common.generateJWTToken()))
          .expect(200)
          .expect('Content-Type', /json/);
      assert.equal(res.body.code, 0);
    });

    it('should not fail with "Not a changeset: undefined" error', async function () {
      // Test with same startRev and endRev (the reported minimal case)
      const res = await agent.get(
          `${endPoint('createDiffHTML')}?padID=${testPadId}&startRev=1&endRev=1`)
          .set("Authorization", (await common.generateJWTToken()))
          .expect(200)
          .expect('Content-Type', /json/);
      assert.equal(res.body.code, 0);
      assert(res.body.data.html != null);
    });

    it('should work with different startRev and endRev', async function () {
      const res = await agent.get(
          `${endPoint('createDiffHTML')}?padID=${testPadId}&startRev=1&endRev=2`)
          .set("Authorization", (await common.generateJWTToken()))
          .expect(200)
          .expect('Content-Type', /json/);
      assert.equal(res.body.code, 0);
      assert(res.body.data.html != null);
    });

    after(async function () {
      await agent.get(`${endPoint('deletePad')}?padID=${testPadId}`)
          .set("Authorization", (await common.generateJWTToken()))
          .expect(200);
    });
  });
});

